mkdirSync(sessionDir, { recursive: true });

console.log("=== End-to-end CHG-0928 v3 test ===\n");

// Step 1: Create session
const sm = SessionManager.create(testCwd, sessionDir);
const sessionFile = sm.getSessionFile();
const trajectoryFile = sessionFile.endsWith(".jsonl")
  ? `${sessionFile.slice(0, -6)}.trajectory.jsonl`
  : `${sessionFile}.trajectory.jsonl`;
console.log(`Session file: ${sessionFile}`);
console.log(`Trajectory file: ${trajectoryFile}`);

// Step 2: Append entries
const userId = randomUUID();
const assistantId = randomUUID();
sm.appendEntry({
  type: "message",
  id: userId,
  parentId: null,
  timestamp: new Date().toISOString(),
  message: { role: "user", content: "CHG-0928 v3 verification." }
});
sm.appendEntry({
  type: "message",
  id: assistantId,
  parentId: userId,
  timestamp: new Date().toISOString(),
  message: {
    role: "assistant",
    content: [{ type: "text", text: "OK." }],
    stopReason: "stop"
  }
});

