  traceSchema: "openclaw-trajectory",
  schemaVersion: 1,
  traceId: randomUUID(),
  source: "runtime",
  type: "session.started",
  ts: new Date().toISOString(),
  seq: 1,
  sourceSeq: 1,
  sessionId: randomUUID(),
  workspaceDir: sanitizeForPersistence(testCwd),
  data: {
    sessionFile: sanitizeForPersistence(sessionFile),
    workspaceDir: sanitizeForPersistence(testCwd)
  }
};
writeFileSync(trajectoryFile, JSON.stringify(trajEvent) + "\n");

// Step 4: Build system prompt with sanitized cwd + sanitized skills
const skills = [
  { name: "notion", description: "Notion API", filePath: sanitizeForPersistence("/Users/ainchorsoc2a/.openclaw/workspace/skills/notion/SKILL.md") },
  { name: "xurl", description: "Twitter research", filePath: sanitizeForPersistence("/Users/ainchorsoc2a/.openclaw/workspace/skills/xurl/SKILL.md") }
];
const sanitizedCwd = sanitizeForPersistence(testCwd).replace(/\\/g, "/");
const skillsPrompt = formatSkillsForPrompt(skills);
const systemPrompt = `${skillsPrompt}\nCurrent working directory: ${sanitizedCwd}`;

// Step 5: Write a context.compiled trajectory event with the system prompt
const ctxEvent = {
  traceSchema: "openclaw-trajectory",
  schemaVersion: 1,
  traceId: randomUUID(),
  source: "runtime",
  type: "context.compiled",
  ts: new Date().toISOString(),
  seq: 2,
  sourceSeq: 2,
  sessionId: randomUUID(),
  workspaceDir: sanitizedCwd,
  data: {
    systemPrompt,
    prompt: "test prompt"
  }
};
writeFileSync(trajectoryFile, JSON.stringify(ctxEvent) + "\n", { flag: "a" });

// Step 6: Verify all files are R01-clean
function check(file) {
  if (!existsSync(file)) return { tilde: -1, abs: -1 };
  const c = readFileSync(file, "utf8");
  return {
    tilde: (c.match(/~\/\.openclaw/g) || []).length,
    abs: (c.match(/\/Users\/ainchorsoc2a\/.openclaw/g) || []).length
  };
}

const sfCheck = check(sessionFile);
const tfCheck = check(trajectoryFile);

console.log(`\n=== Results ===`);
console.log(`Session file (${statSync(sessionFile).size} bytes):`);
console.log(`  ~/.openclaw: ${sfCheck.tilde}`);
console.log(`  /Users/ainchorsoc2a/.openclaw: ${sfCheck.abs}`);
console.log(`Trajectory file (${statSync(trajectoryFile).size} bytes):`);
console.log(`  ~/.openclaw: ${tfCheck.tilde}`);
console.log(`  /Users/ainchorsoc2a/.openclaw: ${tfCheck.abs}`);

const allClean = sfCheck.tilde === 0 && sfCheck.abs === 0 && tfCheck.tilde === 0 && tfCheck.abs === 0;
console.log(`\n=== ${allClean ? "PASS" : "FAIL"} ===`);

// Show first line of session header
console.log(`\nSession header:`);
console.log(readFileSync(sessionFile, "utf8").split("\n")[0]);

// Show first trajectory event (truncated)
console.log(`\nFirst trajectory event (first 400 chars):`);
console.log(readFileSync(trajectoryFile, "utf8").split("\n")[0].slice(0, 400));

process.exit(allClean ? 0 : 1);

