// CHG-0928 v3 (2026-07-19): R01 defense-in-depth. v2 only normalized
// leading `~`/`~/` to an absolute path; that was insufficient because
// callers also persisted the absolute home substring (`/Users/<u>/.openclaw`)
// directly. v3 separates the two concerns:
//   - this.cwd MUST stay a usable absolute path (runtime spawns bash,
//     resolves file reads, etc. against it). Sanitizing it in memory
//     would break tool execution.
//   - Persisted views (session header `cwd`, `parentSession` pointers,
//     trajectory `workspaceDir` / `sessionFile`) are sanitized at the
//     write boundary via `sanitizeForPersistence` (below).
// The constructor only does the tilde expansion needed to make the cwd
// absolute. The header writers at newSession() and forkFrom() apply
// the sanitizer so the JSONL files never carry the forbidden
// `~/.openclaw` or `<home>/.openclaw` substrings.
function normalizeSessionManagerCwd(value) {
	if (typeof value !== "string" || value.length === 0) return value;
	if (value === "~") return os.homedir();
	if (value.startsWith("~/")) return path.resolve(os.homedir(), value.slice(2));
	return value;
}
/**
* CHG-0928 v3: Sanitize a path value for R01-safe persistence. Unlike
* `normalizeSessionManagerCwd`, this DOES rewrite the in-memory value
* into a non-runtime form, so it must only be used at write boundaries
* (session header, trajectory event, JSONL emit) — never for runtime
* filesystem operations.
*/
function sanitizeCwdForPersistence(value) {
	return sanitizeForPersistence(value);
}

