static open(path, sessionDir, cwdOverride) {
	const loaded = revalidateLoadedSessionFile(path, loadEntriesFromFileWithSnapshot(path));
	const header = loaded.entries.find((e) => e.type === "session");
	// CHG-0928 v2/v3: defense-in-depth. v2 expanded leading `~` so
	// reopened sessions with legacy tilde paths couldn't re-inject
	// the violation into subsequent writes. v3 adds: if the loaded
	// header already carries the v3 sanitized form (`$HOME/...`),
	// expand it back to the actual home so the runtime cwd is a
	// usable absolute path (bash spawns, file reads, etc.).
	const rawCwd = cwdOverride ?? header?.cwd ?? process.cwd();
	const cwd = denormalizeSessionManagerCwd(normalizeSessionManagerCwd(rawCwd));
	const dir = sessionDir ?? resolve(path, "..");
	return new SessionManager(cwd, dir, path, true, loaded);
}

